                        >收底调</n-button
                      >
                    </n-gi>
                    <n-gi>
                      <n-button
                        style="width: 120px"
                        @mousedown="continusSendCommand(18)"
                        @mouseup="stopCommand(18)"
                        :disabled="softLock"
                        >降柱抬底</n-button
                      >
                    </n-gi>
                    <n-gi>
                      <n-button
                        style="width: 120px"
                        @mousedown="continusSendCommand(20)"
                        @mouseup="stopCommand(20)"
                        :disabled="softLock"
                        >伸2级护帮板</n-button
                      >
                    </n-gi>
                    <n-gi>
                      <n-button
                        style="width: 120px"
                        @mousedown="continusSendCommand(21)"
                        @mouseup="stopCommand(21)"
                        :disabled="softLock"
                        >收2级护帮板</n-button
                      >
                    </n-gi>
                    <n-gi>
                      <n-button
                        style="width: 120px"
                        @mousedown="continusSendCommand(22)"
                        @mouseup="stopCommand(22)"
                        :disabled="softLock"
                        >伸3级护帮板</n-button
                      >
                    </n-gi>
                    <n-gi>
                      <n-button
                        style="width: 120px"
                        @mousedown="continusSendCommand(23)"
                        @mouseup="stopCommand(23)"
                        :disabled="softLock"
                        >收3级护帮板</n-button
                      >
                    </n-gi>
                  </n-grid>
                </n-gi>
              </n-grid>

              <n-button
                style="width: 120px"
                :type="softLock ? 'error' : 'primary'"
                :loading="softLockLoading"
                @click="handleLock"
                >软件闭锁</n-button
              >
            </n-space>
          </n-card>
        </div>
        <shearer
          style="position: fixed; bottom: 85px"
          :locate="position"
        ></shearer>
      </n-scrollbar>
    </n-layout-content>
    <n-layout-footer bordered position="absolute" class="content-footer">
      <supports
        :active="support"
        :total="counts"
        @selected="selectSupport"
      ></supports>
    </n-layout-footer>
  </n-layout>
</template>

<script setup>
import { h, ref, reactive, computed, onMounted, watch } from "vue";
import { getSoftLock, setSoftLock, setSoftUnlock } from "../../api/request";
import supports from "../../components/supports.vue";
import shearer from "../../components/shearer.vue";
import { Save } from "@vicons/ionicons5";
import { useWsStore } from "../../store/modules/websocket";
import { supportControl } from "../../api/request";
import { useMessage } from "naive-ui";
const message = useMessage();
const wsStore = useWsStore();
const support = ref(1);
const counts = ref(200);
const position = ref(0);
const selectSupport = async (va) => {
  support.value = va;
  // 重新查询软件闭锁状态
  await getSoftLockStatus();
};
//console.log('@@@',selectSupport)
const groupIf = ref(true);
const groupType = ref(2);
//监听煤机位置
watch(() => wsStore.shearer,
  (val) => {
    position.value = Number.parseInt(val.position / 10);
  }
);
const softLock = ref(true);
const softLockLoading = ref(false);
// const handleLock = async () => {
//   softLockLoading.value = true;
//   if (softLock.value) {
//     let { code } = await setSoftUnlock({ targetid: support.value });
//     if (code == 1) {
//       message.error("请登录后操作");
//       softLockLoading.value = false;
//     }
//   } else {
//     let { code } = await setSoftLock({ targetid: support.value });
//     if (code == 2) {
//       message.error("请登录后操作");
//       softLockLoading.value = false;
//     }
//     if (code == 1) {
//       message.error("支架控制器本地闭锁/急停已打开。");
//     }
//   }
// };
const getSoftLockStatus = async () => {
  softLockLoading.value = true;
  let { code, message } = await getSoftLock({ targetid: support.value }); // {code:0,message:{key_status:1,status:1}}
  //console.log('@@@',message);
  softLock.value = message.key_status == 1 ? true : false;
  softLockLoading.value = false;
};
// 进入页面时，问询当前软件闭锁状态
onMounted(async () => {
  await getSoftLockStatus();
});
// 监听websocket的闭锁状态应答
watch(
  () => wsStore.lockStatus,
  async (val) => {
    softLockLoading.value = false;
    if (support.value == val.source) {
      softLock.value = val.msg.key_status == 1 ? true : false;
      if (softLock.value == true) {
        if (interval != null) {
          await stopCommand(0);
        }
      }
    }
  }
);
let interval = null;
const continusSendCommand = async (cmd) => {
  let is_group = groupIf.value ? 1 : 0;
  if (is_group > 0) {
    is_group = groupType.value;
  }
  await supportControl({
    target_id: support.value,
    command: cmd,
    is_run: 1,
    
  });
  if (interval == null) {
    interval = setInterval(async function () {
      let { code } = await supportControl({
        target_id: support.value,
        command: cmd,
        is_run: 1,
        
      });
      if (code != 0) {
        if (interval != null) {
          clearInterval(interval);
          interval = null;
        }
        message.error("请登录后操作");
      }
    }, 300);
  }
};
const stopCommand = async (cmd) => {
  let is_group = groupIf.value ? 1 : 0;
  if (is_group > 0) {
    is_group = groupType.value;
  }
  if (interval != null) {
    clearInterval(interval);
    interval = null;
  }
  let { code } = await supportControl({
    target_id: support.value,
    command: cmd,
    is_run: 0,
    
  });
  if (code != 0) {
    message.error("请登录后操作");
  }
};
</script>

<style lang="scss" scoped>
.content {
  height: 100%;
  position: relative;
  &-center {
    position: absolute;
    top: 0;
    width: 100%;
    bottom: 60px;
    &-form {
      margin: 20px;
      text-align: center;
    }
  }
  &-footer {
    height: 56px;
    color: #cba;
    text-align: center;
    position: absolute;
    bottom: 0px;
    width: 100%;
  }
}
</style>